class Solution:
    def numberOfStableArrays(self, zero: int, one: int, limit: int) -> int:
        MOD = 10**9 + 7
        @lru_cache(None)
        def dp(z, o, lst):
            if z == 0 and o == 0: return 1
            res = 0
            if z > 0 and (lst != 0 or z <= limit):
                res += dp(z-1, o, 0)
            if o > 0 and (lst != 1 or o <= limit):
                res += dp(z, o-1, 1)
            return res % MOD

        return (dp(zero, one, -1)) % MOD
